// Session log JSONL schema reference.
//
// The agent harness writes one event per line to .ddx/agent-logs/agent-*.jsonl
// (or to the per-run SessionLogDir override). Every line has the envelope:
//
//	{"session_id": string, "seq": int, "type": string, "ts": RFC3339Nano, "data": {...}}
//
// The standard schema is always emitted and is what existing tooling consumes.
// Diagnostic logging is opt-in via DDX_LOG_VERBOSE=1; when set, the writer adds
// raw body fields so a session can be replayed and root-caused without loss of
// inputs and outputs. Diagnostic fields are strictly additive: event ordering
// and event types stay the same across harnesses.
//
// Per-event-type fields:
//
//	session.start:
//	  data.model       string  — model id reported by the harness
//	  data.session_id  string  — session id from the harness CLI
//	  data.bead_id     string  — bead under which the session ran (may be "")
//	  data.elapsed_ms  int     — ms since session start (always 0 here)
//	  data.harness     string  — "claude" | "fiz" | etc.
//
//	llm.request:
//	  data.attempt_index int        — request attempt counter (0-based)
//	  data.messages      []object   — conversation messages (last user message hint used by the renderer)
//
//	llm.response:
//	  data.model         string  — resolved model id
//	  data.latency_ms    int     — per-call wall time (request → response)
//	  data.tool_calls    []{name} — tool_use names emitted in this turn
//	  data.turn          int     — 1-based assistant turn count
//	  data.bead_id       string
//	  data.elapsed_ms    int     — ms since session start
//	  data.input_tokens  int     — running input tokens (latest seen)
//	  data.output_tokens int     — running output tokens (latest seen)
//	  data.attempt.cost.raw.total_tokens int — running total
//
//	llm.response (diagnostic adds):
//	  data.content       string  — concatenated assistant text blocks for this turn
//	  data.finish_reason string  — claude stop_reason ("end_turn", "tool_use", "max_tokens", ...)
//	  data.usage object:
//	    input_tokens                int
//	    output_tokens               int
//	    cache_creation_input_tokens int
//	    cache_read_input_tokens     int
//	    total_tokens                int
//
//	tool.call:
//	  data.tool       string         — tool name
//	  data.input      object         — tool arguments as decoded JSON
//	  data.bead_id    string
//	  data.elapsed_ms int            — ms since session start
//	  data.turn       int            — assistant turn that issued the call
//
//
//	tool.result:
//	  data.tool         string
//	  data.output_bytes int
//	  data.output_excerpt string — compact first-line excerpt safe for progress logs
//	  data.duration_ms  int     — wall time from tool_use → tool_result
//	  data.error        string  — non-empty when tool_result is_error=true; empty otherwise
//	  data.bead_id      string
//	  data.elapsed_ms   int
//	  data.turn         int
//
//	tool.result (diagnostic adds):
//	  data.output string — tool_result content (joined if structured)
//
// Diagnostic logging is off by default; existing consumers of the standard
// schema (TailSessionLogs, FormatSessionLogLines, the server worker log
// endpoint) keep working unchanged because they tolerate extra fields.

// FormatSessionLogLines formats Fizeau-style JSONL log entries into readable progress.
// It is used by both the CLI (local execute-loop) and the server worker log endpoint.
func FormatSessionLogLines(lines []string) string {
	var sb strings.Builder
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		var entry map[string]any
		if err := json.Unmarshal([]byte(line), &entry); err != nil {
			continue
		}
		entryType, _ := entry["type"].(string)
		switch entryType {
		case "session.start":
			model, _ := entry["data"].(map[string]any)["model"].(string)
			fmt.Fprintf(&sb, "▶ session started (model: %s)\n", model)
		case "llm.request":
			data, _ := entry["data"].(map[string]any)
			attemptIdx, _ := data["attempt_index"].(float64)
			requestBytes := encodedPayloadSize(data["messages"])
			// Extract a hint from the last user message in the conversation.
			promptHint := ""
			if msgs, ok := data["messages"].([]any); ok {
				for i := len(msgs) - 1; i >= 0; i-- {
					if msg, ok := msgs[i].(map[string]any); ok {
						if role, _ := msg["role"].(string); role == "user" {
							if content, _ := msg["content"].(string); content != "" {
								promptHint = " [" + truncateStr(strings.TrimSpace(content), 60) + "]"
							}
							break
						}
					}
				}
			}
			sizeHint := formatSizeSuffix("req", requestBytes)
			fmt.Fprintf(&sb, "  → llm request (attempt %.0f%s)%s\n", attemptIdx, sizeHint, promptHint)
		case "llm.response":
			data, _ := entry["data"].(map[string]any)
			model, _ := data["model"].(string)
			latency, _ := data["latency_ms"].(float64)
			responseBytes := progressInt(data, "response_bytes")
			if responseBytes <= 0 {
				responseBytes = encodedPayloadSize(data["content"])
			}
			thinkingBytes := progressInt(data, "thinking_bytes")
			toolInputBytes := progressInt(data, "tool_input_bytes")
			// Tokens: data.attempt.cost.raw.total_tokens
			var tokens float64
			if attempt, ok := data["attempt"].(map[string]any); ok {
				if cost, ok := attempt["cost"].(map[string]any); ok {
					if raw, ok := cost["raw"].(map[string]any); ok {
						tokens, _ = raw["total_tokens"].(float64)
					}
				}
			}
			// Tool calls from response
			toolCalls, _ := data["tool_calls"].([]any)
			finishReason, _ := data["finish_reason"].(string)
			suffix := ""
			if len(toolCalls) > 0 {
				var names []string
				for _, tc := range toolCalls {
					if tcm, ok := tc.(map[string]any); ok {
						n, _ := tcm["name"].(string)
						if n != "" {
							names = append(names, n)
						}
					}
				}
				suffix = fmt.Sprintf(" → %s", strings.Join(names, ", "))
			} else if finishReason != "" {
				suffix = fmt.Sprintf(" (%s)", finishReason)
			}
			byteHints := formatPayloadHints([]payloadHint{
				{label: "text", bytes: responseBytes},
				{label: "think", bytes: thinkingBytes},
				{label: "tool_in", bytes: toolInputBytes},
			})
			if byteHints != "" {
				byteHints = ", " + byteHints
			}
			throughput := formatTokenThroughput(int(tokens), int(latency))
			if throughput != "" {
				throughput = ", " + throughput
			}
			fmt.Fprintf(&sb, "  ← llm response (%.0f tokens, %.1fs%s%s) %s%s\n", tokens, latency/1000, throughput, byteHints, model, suffix)
		case "llm.delta":
			// Skip deltas — too verbose for summary
		case "progress":
			if line := formatProgressLogEntry(entry); line != "" {
				fmt.Fprint(&sb, line)
			}
		case "tool.call":
			data, _ := entry["data"].(map[string]any)
			name, _ := data["tool"].(string)
			inp, _ := data["input"].(map[string]any)
			dur, _ := data["duration_ms"].(float64)
			inputBytes := progressInt(data, "input_bytes")
			if inputBytes <= 0 {
				inputBytes = encodedPayloadSize(inp)
			}
			output, _ := data["output"].(string)
			outputBytes := progressInt(data, "output_bytes")
			if outputBytes <= 0 {
				outputBytes = len([]byte(output))
			}
			argHint := ""
			if len(inp) > 0 {
				// Prefer path/command/query keys for display
				for _, key := range []string{"path", "command", "query", "file"} {
					if v, ok := inp[key]; ok {
						argHint = fmt.Sprintf("%v", v)
						break
					}
				}
				if argHint == "" {
					for _, v := range inp {
						argHint = fmt.Sprintf("%v", v)
						break
					}
				}
				argHint = compactToolDisplay("", argHint)
			}
			errMsg, _ := data["error"].(string)
			errSuffix := ""
			if errMsg != "" {
				errSuffix = fmt.Sprintf(" ❌ %s", truncateStr(errMsg, 40))
			}
			durSuffix := ""
			if dur > 0 {
				durSuffix = fmt.Sprintf(" (%.1fs)", dur/1000)
			}
			sizeSuffix := formatPayloadHints([]payloadHint{
				{label: "in", bytes: inputBytes},
				{label: "out", bytes: outputBytes},
			})
			if sizeSuffix != "" {
				sizeSuffix = " " + sizeSuffix
			}
			fmt.Fprintf(&sb, "  🔧 %s %s%s%s%s\n", name, argHint, sizeSuffix, durSuffix, errSuffix)
		case "tool.result", "tool_result":
			data, _ := entry["data"].(map[string]any)
			name, _ := data["tool"].(string)
			if name == "" {
				name, _ = data["name"].(string)
			}
			output, _ := data["output"].(string)
			outputBytes := progressInt(data, "output_bytes")
			if outputBytes <= 0 {
				outputBytes = len([]byte(output))
			}
			dur, _ := data["duration_ms"].(float64)
			errMsg, _ := data["error"].(string)
			durSuffix := ""
			if dur > 0 {
				durSuffix = " " + (time.Duration(int64(dur)) * time.Millisecond).String()
			}
			errSuffix := ""
			if errMsg != "" {
				errSuffix = " failed"
			}
			name = compactToolDisplay(name, "")
			excerpt := compactOutputExcerpt(data)
			if excerpt != "" {
				excerpt = " " + excerpt
			}
			fmt.Fprintf(&sb, "  < %s out=%s%s%s%s\n",
				name, formatByteSize(outputBytes), excerpt, durSuffix, errSuffix)
		case "bead.claimed":
			data, _ := entry["data"].(map[string]any)
			beadID, _ := data["bead_id"].(string)
			title, _ := data["title"].(string)
			if title != "" {
				fmt.Fprintf(&sb, "\n▶ %s: %s\n", beadID, title)
			} else {
				fmt.Fprintf(&sb, "\n▶ %s\n", beadID)

						if textOut.Len() > 0 {
							textOut.WriteString("\n")
						}
						textOut.WriteString(block.Text)
						responseBytes += len([]byte(block.Text))
					}
				case "thinking":
					if block.Thinking != "" {
						thinkingBytes += len([]byte(block.Thinking))
					}
				case "tool_use":
					name := block.Name
					if name == "" {
						name = "tool"
					}
					toolNames = append(toolNames, map[string]string{"name": name})
					toolInputBytes += len(block.Input)
				}
			}

			latencyMS := now.Sub(lastRequestSentAt).Milliseconds()
			if latencyMS < 0 {
				latencyMS = 0
			}
			llmData := map[string]any{
				"model":            res.Model,
				"latency_ms":       latencyMS,
				"tool_calls":       toolNames,
				"turn":             res.TurnCount,
				"bead_id":          beadID,
				"elapsed_ms":       elapsedMS,
				"input_tokens":     res.InputTokens,
				"output_tokens":    res.OutputTokens,
				"response_bytes":   responseBytes,
				"thinking_bytes":   thinkingBytes,
				"tool_input_bytes": toolInputBytes,
				"attempt": map[string]any{
					"cost": map[string]any{
						"raw": map[string]any{
							"total_tokens": res.InputTokens + res.OutputTokens,
						},
					},
				},
			}
			if verbose {
				llmData["content"] = textOut.String()
				llmData["finish_reason"] = msg.Stop
				llmData["usage"] = map[string]any{
					"input_tokens":                msg.Usage.InputTokens,
					"output_tokens":               msg.Usage.OutputTokens,
					"cache_creation_input_tokens": msg.Usage.CacheCreationInputTokens,
					"cache_read_input_tokens":     msg.Usage.CacheReadInputTokens,
					"total_tokens":                msg.Usage.InputTokens + msg.Usage.OutputTokens,
				}
			}
			data, _ := json.Marshal(llmData)
			emit("llm.response", string(data))

			// Emit tool.call immediately for every tool_use block. The
			// matching user/tool_result event emits tool.result later.
			for _, block := range msg.Content {
				if block.Type != "tool_use" {
					continue
				}
				res.ToolCalls++
				input := map[string]any{}
				if len(block.Input) > 0 {
					_ = json.Unmarshal(block.Input, &input)
				}
				pendingTools[block.ID] = &pendingToolCall{
					name:      block.Name,
					input:     input,
					startedAt: now,
					turn:      res.TurnCount,
					elapsedMS: elapsedMS,
				}
				toolData, _ := json.Marshal(map[string]any{
					"tool":        block.Name,
					"input":       input,
					"input_bytes": len(block.Input),
					"bead_id":     beadID,
					"elapsed_ms":  elapsedMS,
					"turn":        res.TurnCount,
				})
				emit("tool.call", string(toolData))
			}

			// Save the most recent text content so, if the final result
			// event is missing or truncated, we can still return the
			// agent's last spoken text.
			if t := textOut.String(); t != "" {
				res.FinalText = t
			}

		case "user":
			// user events carry tool_result content. They mark the moment
			// the next LLM request is sent, so we reset the per-call
			// latency baseline.
			if len(ev.Message) > 0 && len(pendingTools) > 0 {
				var um claudeUserMessage
				if json.Unmarshal(ev.Message, &um) == nil {
					for _, blk := range um.Content {
						if blk.Type != "tool_result" || blk.ToolUseID == "" {
							continue
						}
						pending, ok := pendingTools[blk.ToolUseID]
						if !ok {
							continue
						}
						delete(pendingTools, blk.ToolUseID)
						output := decodeToolResultContent(blk.Content)
						errMsg := ""
						if blk.IsError {
							errMsg = output
						}
						durationMS := now.Sub(pending.startedAt).Milliseconds()
						if durationMS < 0 {
							durationMS = 0
						}
						resultPayload := map[string]any{
							"tool":           pending.name,
							"output_bytes":   len([]byte(output)),
							"output_excerpt": outputSummaryFromRaw(output),
							"duration_ms":    durationMS,
							"error":          errMsg,
							"bead_id":        beadID,
							"elapsed_ms":     elapsedMS,
							"turn":           pending.turn,
						}
						if verbose {
							resultPayload["output"] = output
						}
						resultData, _ := json.Marshal(resultPayload)
						emit("tool.result", string(resultData))
					}
				}
			}
			lastRequestSentAt = now

		case "result":
			// Final event. Extract authoritative usage/cost/result text.
			if ev.Result != "" {
				res.FinalText = ev.Result
			}
			if ev.Usage.InputTokens > 0 {
				res.InputTokens = ev.Usage.InputTokens
			}
			if ev.Usage.OutputTokens > 0 {
				res.OutputTokens = ev.Usage.OutputTokens
			}
			if ev.TotalCostUSD > 0 {
				res.CostUSD = ev.TotalCostUSD
			}
			if ev.SessionID != "" {
				res.SessionID = ev.SessionID
			}
			if ev.IsError {
				res.IsError = true
			}
		}
	}
	if err := scanner.Err(); err != nil && !errors.Is(err, io.EOF) {
		return res, err
	}
	// Flush any tool calls whose tool_result never arrived (stream truncated
	// or the model made a tool call as its final action).
	if len(pendingTools) > 0 {
		flushAt := time.Now()
		for _, pending := range pendingTools {
			resultPayload := map[string]any{
				"tool":           pending.name,
				"output_bytes":   0,
				"output_excerpt": "",
				"duration_ms":    flushAt.Sub(pending.startedAt).Milliseconds(),
				"error":          "no tool_result received",
				"bead_id":        beadID,
				"elapsed_ms":     pending.elapsedMS,
				"turn":           pending.turn,
			}
			if verbose {
				resultPayload["output"] = ""
			}
			resultData, _ := json.Marshal(resultPayload)
			emit("tool.result", string(resultData))
		}
	}
	return res, nil
}

// decodeToolResultContent normalizes the polymorphic tool_result.content
// field (either a string or an array of {type:"text",text:"..."} blocks)
// into a single string suitable for the diagnostic tool.result output field.
func decodeToolResultContent(raw json.RawMessage) string {
	if len(raw) == 0 {
		return ""
	}
	var s string
	if err := json.Unmarshal(raw, &s); err == nil {
		return s
	}
	var blocks []struct {
		Type string `json:"type"`
		Text string `json:"text"`
	}
	if err := json.Unmarshal(raw, &blocks); err == nil {
		var sb strings.Builder
		for i, b := range blocks {
			if i > 0 {
				sb.WriteString("\n")
			}
			sb.WriteString(b.Text)
		}
		return sb.String()
	}
	return string(raw)
}

// resolveClaudeProgressLogDir picks the directory for the per-run claude
// progress JSONL trace. The per-run override (opts.SessionLogDir) takes
// precedence over the runner-wide Config.SessionLogDir so managed
// execute-bead invocations can redirect the trace into the DDx-owned
// execution bundle's embedded/ dir instead of the runner's default
// .ddx/agent-logs. Matches the agent_runner.go precedence pattern so the
// two harnesses behave identically under execute-bead.
func resolveClaudeProgressLogDir(opts RunArgs, cfg Config) string {
	if opts.SessionLogDir != "" {
		return opts.SessionLogDir
	}
	return cfg.SessionLogDir
}

// runClaudeStreaming is the streaming execution path for the claude harness.
// It launches the claude binary directly (bypassing the standard Executor
// abstraction so it can pipe stdout line-by-line), parses stream-json events
// as they arrive, and writes per-tool progress entries to a Fizeau-style
// JSONL file in opts.SessionLogDir (when set) or r.Config.SessionLogDir so
// `ddx server workers log` sees real-time activity.
//
// On success it returns a *Result shaped exactly like the non-streaming
// path, so callers downstream (processResult, session logging) are unchanged.
//
// If the claude CLI rejects the stream-json flags (older build, unsupported
// option), the caller falls back to the non-streaming path via
// runClaudeWithFallbackFn.
