// QuotaStateFromUsedPercent maps a usage percentage to a quota state string.
func QuotaStateFromUsedPercent(usedPercent int) string {
	if usedPercent >= 95 {
		return "blocked"
	}
	if usedPercent >= 0 {
		return "ok"
	}
	return "unknown"
}

