	case "tool":
		return formatToolProgressLine(state, data)
	case "response":
		return formatResponseProgressLine(state, data)
	case "context":
		return formatContextProgressLine(state, data)
	case "compaction":
		return formatCompactionProgressLine(state, data)
	default:
		return ""
	}
