					"tool_name":      "apply_patch",
					"action":         "add test implementation",
					"target":         "cli/internal/file.go",
					"command":        "apply_patch",
					"output_summary": "out=312B 12 lines \"Success. Updated the following files:\"",
					"duration_ms":    35,
