			name: "native tool result with verbose raw output trims body",
			lines: []string{
				mustSessionLogLine(t, "tool.result", map[string]any{
					"tool":         "bash",
					"output":       "ok github.com/DocumentDrivenDX/ddx/internal/agent 0.014s\n" + longTail,
